# Geometry module - shapes hierarchy with abstract base classes
import utilities

@abstract
class Shape:
    """Base class for all geometric shapes."""
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

@abstract
class Polygon(Shape):
    """Base class for polygon shapes with sides."""
    sides: int

    def __init__(self, name: str, sides: int):
        super().__init__(name)
        self.sides = sides

    @override
    def describe(self) -> str:
        base_desc: str = super().describe()
        return f"{base_desc} with {self.sides} sides"

class Rectangle(Polygon):
    """Rectangle shape with width and height."""
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle", 4)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape):
    """Circle shape with radius."""
    radius: float

    @static
    property get PI() -> float:
        return 3.14159

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def area(self) -> float:
        return Circle.PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        # Circumference
        return 2.0 * Circle.PI * self.radius

def create_rectangle(width: float, height: float) -> Rectangle:
    """Factory function for rectangles."""
    return Rectangle(width, height)

def total_area(shapes: list[Shape]) -> float:
    """Calculate total area of all shapes."""
    total: float = 0.0
    for shape in shapes:
        total = total + shape.area()
    return total
